  if (!record) return null;
  return {
    failureReason: record.failureReason,
    quarantinedAt: record.quarantinedAt,
    quarantineStatus: record.quarantineStatus,
    caConnectionId: record.caConnectionId,
  };
}

export {
  // Low-level gates
  publicGate,
  ownGate,
  assignedGate,
  managedRaceGate,
  adminGate,
  isOwn,
  isAssigned,
  isManagedRace,
  isSystem,
  // Authenticity
  authenticityFilter,
  quarantineSummaryFilter,
  // Unified
  auth,
};
