{"content":"// Browser-compatible DEV-1 test modules.
// Exposed as window.ARY_TEST = { stores, auth, stateMachine, caVerifier }
// These mirror project/src/*.js but avoid Node-specific APIs (no crypto.randomUUID for UUIDs, no node: imports).

(function () {
  "use strict";

  // --- UUID helper ---
  function uid() {
    return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g, (c) => {
      const r = (Math.random() * 16) | 0;
      const v = c === "x" ? r : (r & 0x3) | 0x8;
      return v.toString(16);
    });
  }
  function now() {
    return new Date().toISOString();
  }

  // --- Simple hash ---
  function simpleHash(str) {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      const ch = str.charCodeAt(i);
      hash = (hash << 5) - hash + ch;
      hash |= 0;
    }
    return hash.toString(16);
  }

  // ============ STORES ============
  function createStore(name, uniqueIndexes) {
    const data = new Map();
    const indexes = {};
    for (const idx of uniqueIndexes) {
      indexes[idx.name] = { fields: idx.fields, map: new Map() };
    }

    function idxKey(record, fields) {
      return fields.map((f) => record[f]).join("::");
    }

    function checkUnique(record) {
      for (const [idxName, idx] of Object.entries(indexes)) {
        const k = idxKey(record, idx.fields);
        if (idx.map.has(k)) return { ok: false, reason: "UNIQUE_" + idxName + ": " + k, key: k };
      }
      return { ok: true };
    }

    function updateIndexes(record, op) {
