    function validMsg(o) { const body={event:"task_completed",taskId:"t1"}; const n=caVerifier.normalizeBody(body); return {appInstanceId:"app-001",deviceKeyId:"key-001",nonce:uid(),sequence:Math.floor(Math.random()*100000)+1000,timestamp:ts(-1000),caConnectionId:cc.id,messageId:uid(),idempotencyKey:uid(),schemaVersion:"ary.ca.riding_signal.v0.1",signature:{algorithm:"ecdsa-p256",bodyHash:simpleHash(n),value:"valid-sig-abcdef"},body,...o}; function simpleHash(s){let h=0;for(let i=0;i<s.length;i++){h=(h<<5)-h+s.charCodeAt(i);h|=0} return h.toString(16)} }
