  });

  // --- AC-5 ---
  describe("AC-5: CA 接入失败不阻断主流程", (s) => {
    it("AC-5.1 — not_configured 时仍可提交 Work", () => { const reg=seedRegistration({status:"approved"}); const rp=seedRaceProject({registrationId:reg.id,aggregateIngestionStatus:"not_configured",connectionHealth:"no_signal"}); seedRace({id:rp.raceId,status:"running"}); const w=seedWork({registrationId:reg.id,raceId:rp.raceId,ownerUserId:reg.userId,status:"draft"}); const u=stores.works.update(w.id,{status:"submitted",submittedAt:now()}); assert.ok(u.ok); const f=stateMachine.generateReviewFlags(rp); assert.ok(f.find((x)=>x.flagType==="ca_unconfigured")); });
    it("AC-5.2 — 全部 CAConnection failed 时仍可提交 Work", () => { const reg=seedRegistration({status:"approved"}); const rp=seedRaceProject({registrationId:reg.id,aggregateIngestionStatus:"failed",connectionHealth:"all_failed"}); seedRace({id:rp.raceId,status:"running"}); const w=seedWork({registrationId:reg.id,raceId:rp.raceId,ownerUserId:reg.userId,status:"draft"}); stores.works.update(w.id,{status:"submitted",submittedAt:now()}); const flags=stateMachine.generateReviewFlags(rp); assert.ok(flags.find((x)=>x.flagType==="ca_failed")); assert.equal(stores.registrations.get(reg.id).status,"approved"); });
    it("AC-5.3 — CA 接入异常时仍可进入评审", () => { const reg=seedRegistration({status:"approved"}); const rp=seedRaceProject({registrationId:reg.id,aggregateIngestionStatus:"failed"}); seedRace({id:rp.raceId,status:"judging"}); const w=seedWork({registrationId:reg.id,raceId:rp.raceId,ownerUserId:reg.userId,status:"locked"}); const j=seedUser({roles:["judge"]}); const as=stores.judgeAssignments.insert({id:uid(),raceId:rp.raceId,workId:w.id,judgeUserId:j.id,assignedByUserId:uid(),status:"assigned",assignedAt:now(),completedAt:null,createdAt:now(),updatedAt:now(),version:1}); const rec=stores.judgingRecords.insert({id:uid(),judgeAssignmentId:as.record.id,workId:w.id,judgeUserId:j.id,scoreResult:{},scoreRiding:{},comments:"评审通过",status:"draft",submittedAt:null,createdAt:now(),updatedAt:now(),version:1}); assert.ok(rec.ok); stores.judgingRecords.update(rec.record.id,{status:"submitted",submittedAt:now()}); });
    it("AC-5.4 — CA 接入异常时仍可颁发 Award", () => { const reg=seedRegistration({status:"approved"}); const rp=seedRaceProject({registrationId:reg.id,aggregateIngestionStatus:"failed"}); const aw=stores.awards.insert({id:uid(),raceId:rp.raceId,registrationId:reg.id,workId:null,awardName:"Best Effort",rank:1,decisionReason:"尽管 CA 未接入",status:"draft",publishedAt:null,createdAt:now(),updatedAt:now(),version:1}); assert.ok(aw.ok); const pub=stores.awards.update(aw.record.id,{status:"published",publishedAt:now()}); assert.ok(pub.ok); });
    it("AC-5.5 — 风险提示生成验证", () => { const rp=seedRaceProject({aggregateIngestionStatus:"not_configured",connectionHealth:"no_signal"}); const f=stateMachine.generateReviewFlags(rp); assert.ok(f.length>0); assert.equal(f[0].flagType,"ca_unconfigured"); assert.equal(f[0].resolved,false); });
    it("AC-5.6 — 部分 CAConnection 正常时风险提示降级", () => { const rp=seedRaceProject({aggregateIngestionStatus:"active",connectionHealth:"partial_failed"}); const f=stateMachine.generateReviewFlags(rp); assert.ok(f.filter((x)=>x.flagType==="ca_failed").length>0); assert(!f.find((x)=>x.flagType==="ca_unconfigured")); });
    it("AC-5.7 — CA 接入状态不得驱动 Registration 进入 withdrawn", () => { const reg=seedRegistration({status:"approved"}); seedRaceProject({registrationId:reg.id,aggregateIngestionStatus:"failed"}); assert.ok(stateMachine.registrationCanTransition("approved","withdrawn").ok); const blocked=stateMachine.registrationCanTransition("submitted","withdrawn"); assert(!blocked.ok); assert.match(blocked.reason,/不驱动/); assert.equal(stores.registrations.get(reg.id).status,"approved"); });
  });

  // --- State Machine ---
  describe("状态机", (s) => {
    it("Race: draft → published → registration → running", () => { assert.ok(stateMachine.raceCanTransition("draft","published").ok); assert.ok(stateMachine.raceCanTransition("published","registration").ok); assert.ok(stateMachine.raceCanTransition("registration","running").ok); });
    it("Race: 禁止 completed → judging 回退", () => { const r=stateMachine.raceCanTransition("completed","judging"); assert(!r.ok); assert.match(r.reason,/回退/); });
    it("Race: 禁止跳过 published 直接进入 registration", () => { assert(!stateMachine.raceCanTransition("draft","registration").ok); });
    it("Registration: submitted → approved → withdrawn", () => { assert.ok(stateMachine.registrationCanTransition("submitted","approved").ok); assert.ok(stateMachine.registrationCanTransition("approved","withdrawn").ok); });
    it("Work: draft → submitted → locked", () => { assert.ok(stateMachine.workCanTransition("draft","submitted").ok); assert.ok(stateMachine.workCanTransition("submitted","locked").ok); });
    it("Work: 禁止 locked → draft", () => { assert(!stateMachine.workCanTransition("locked","draft").ok); });
    it("JudgingRecord: draft → submitted", () => { assert.ok(stateMachine.judgingCanTransition("draft","submitted").ok); });
    it("JudgingRecord: 禁止 submitted → draft", () => { assert(!stateMachine.judgingCanTransition("submitted","draft").ok); });
    it("Award: draft → published → withdrawn", () => { assert.ok(stateMachine.awardCanTransition("draft","published").ok); assert.ok(stateMachine.awardCanTransition("published","withdrawn").ok); });
    it("Award: 禁止 published → draft", () => { assert(!stateMachine.awardCanTransition("published","draft").ok); });
    it("RaceProject ingestion: not_configured → connected → active → failed → connected", () => { assert.ok(stateMachine.rpIngestionCanTransition("not_configured","connected").ok); assert.ok(stateMachine.rpIngestionCanTransition("connected","active").ok); assert.ok(stateMachine.rpIngestionCanTransition("active","failed").ok); assert.ok(stateMachine.rpIngestionCanTransition("failed","connected").ok); });
    it("computeConnectionHealth: no_signal → ok → partial_failed → all_failed", () => { assert.equal(stateMachine.computeConnectionHealth([]),"no_signal"); assert.equal(stateMachine.computeConnectionHealth(["connected"]),"ok"); assert.equal(stateMachine.computeConnectionHealth(["active","failed"]),"partial_failed"); assert.equal(stateMachine.computeConnectionHealth(["failed","failed"]),"all_failed"); });
  });

  // --- Auth ---
  describe("鉴权作用域", (s) => {
    it("ownGate — User 只能访问自己的资源", () => { const u=seedUser({roles:["rider"]}); assert.ok(auth.ownGate({userId:u.id},u)); assert(!auth.ownGate({userId:uid()},u)); });
    it("assignedGate — Judge 只能访问已分配的作品", () => { const j=seedUser({roles:["judge"]}); const w=seedWork(); assert(!auth.assignedGate(w.id,j)); stores.judgeAssignments.insert({id:uid(),raceId:uid(),workId:w.id,judgeUserId:j.id,assignedByUserId:uid(),status:"assigned",assignedAt:now(),completedAt:null,createdAt:now(),updatedAt:now(),version:1}); assert.ok(auth.assignedGate(w.id,j)); });
    it("managedRaceGate — Organizer 只能管理自己的 Race", () => { const o=seedUser({roles:["organizer"]}); const r=seedRace({organizerUserIds:[o.id],createdByUserId:o.id}); assert.ok(auth.managedRaceGate({raceId:r.id},o)); assert(!auth.managedRaceGate({raceId:uid()},o)); });
    it("adminGate — Admin 拥有 system 权限", () => { const a=seedUser({roles:["admin"]}); const u=seedUser({roles:["rider"]}); assert.ok(auth.adminGate(a)); assert(!auth.adminGate(u)); });
  });

  // ================ RUNNER ================
  function resetAll() { resetAllStores(); resetKeys(); renderGroups(); updateSummary(); }

  let results = [];
  function renderGroups() {
    const el = document.getElementById("results");
    el.innerHTML = suites.map((g, gi) =>
      `<div class="group"><div class="group-title">${g.title}</div>` +
      g.tests.map((t, ti) => {
        const r = results[gi]?.[ti];
        const cls = r ? (r.pass ? "pass" : "fail") : "pending";
        const icon = r ? (r.pass ? "✓" : "✗") : "—";
        const msg = r && !r.pass ? `<div class="msg">${r.error || ""}</div>` : "";
        const dur = r ? `<span class="dur">${r.dur.toFixed(1)}ms</span>` : "";
        return `<div class="test-row ${cls}" id="test-${gi}-${ti}"><span class="icon">${icon}</span><span class="name">${t.title}</span>${dur}${msg}</div>`;
      }).join("") + `</div>`
    ).join("");
  }

  function updateSummary() {
    let total=0, pass=0, fail=0;
    for (const g of results) for (const t of (g || [])) { total++; if (t.pass) pass++; else fail++; }
    document.getElementById("summary").innerHTML = `
      <div class="summary-card"><b>${total}</b><span>总计</span></div>
      <div class="summary-card pass"><b>${pass}</b><span>通过</span></div>
      <div class="summary-card fail"><b>${fail}</b><span>失败</span></div>
      <div class="summary-card"><b>${total?((pass/total*100).toFixed(0)):0}%</b><span>通过率</span></div>`;
  }

  async function runAll() {
    resetAll();
    results = [];
    renderGroups();
    updateSummary();

    for (let gi = 0; gi < suites.length; gi++) {
      results[gi] = [];
      const group = suites[gi];
      for (let ti = 0; ti < group.tests.length; ti++) {
        const test = group.tests[ti];
        const el = document.getElementById(`test-${gi}-${ti}`);
        if (el) { el.className = "test-row running"; el.querySelector(".icon").textContent = "◌"; }

        const start = performance.now();
        let pass = true, error = "";
        try {
          test.fn();
        } catch (e) {
          pass = false;
          error = e.message || String(e);
        }
        const dur = performance.now() - start;
        results[gi][ti] = { pass, dur, error };

        if (el) {
          el.className = "test-row " + (pass ? "pass" : "fail");
          el.querySelector(".icon").textContent = pass ? "✓" : "✗";
          if (!pass) el.innerHTML += `<div class="msg">${error}</div>`;
          const durEl = el.querySelector(".dur");
          if (durEl) durEl.textContent = dur.toFixed(1) + "ms";
          else el.innerHTML += `<span class="dur">${dur.toFixed(1)}ms</span>`;
        }
        await new Promise((r) => setTimeout(r, 1));
        updateSummary();
      }
    }
  }

  // Init
  resetAll();
  renderGroups();
  updateSummary();
</script>
</body>
