{"content":"// ARY MVP — Application Core
// Loads DEV-1 modules and wires them to the UI.
// This replaces the static prototype data rendering with live business logic.

(function () {
  "use strict";

  const { uid, now, stores, resetAll, auth, stateMachine, caVerifier } = window.ARY_TEST;

  // ============ App State ============
  const App = {
    currentUser: null,      // { id, displayName, roles[], ... }
    currentRaceId: null,
    page: "home",
  };

  // ============ Seed demo data ============
  function seedDemoData() {
    resetAll();
    caVerifier.resetKeys();

    // Users
    const alice = stores.users.insert({ id: uid(), githubAccountId: "gh-alice", slug: "alice", displayName: "Alice Chen", profile: { bio: "HKU CS / 大三", avatarUrl: "" }, roles: ["rider"], profileCompletionStatus: "complete", status: "active", createdAt: now(), updatedAt: now(), version: 1 }).record;
    const bob = stores.users.insert({ id: uid(), githubAccountId: "gh-bob", slug: "bob", displayName: "Bob Xu", profile: { bio: "FinTech Studio", avatarUrl: "" }, roles: ["rider", "judge"], profileCompletionStatus: "complete", status: "active", createdAt: now(), updatedAt: now(), version: 1 }).record;
    const carol = stores.users.insert({ id: uid(), githubAccountId: "gh-carol", slug: "carol", displayName: "Carol Wang", profile: { bio: "赛事主办方", avatarUrl: "" }, roles: ["organizer"], profileCompletionStatus: "complete", status: "active", createdAt: now(), updatedAt: now(), version: 1 }).record;
    const admin = stores.users.insert({ id: uid(), githubAccountId: "gh-admin", slug: "admin", displayName: "Admin", profile: {}, roles: ["admin"], profileCompletionStatus: "complete", status: "active", createdAt: now(), updatedAt: now(), version: 1 }).record;

    // Races
    const race1 = stores.races.insert({ id: uid(), slug: "bay-area-happy-trip", title: "湾区开心游", challengeBrief: "构建大湾区旅行伴随 Agent", status: "registration", timeWindows: { registrationStart: "2026-06-01", registrationEnd: "2026-07-15", raceStart: "2026-07-20", raceEnd: "2026-08-20", submissionDeadline: "2026-08-15", judgingStart: "2026-08-21", judgingEnd: "2026-09-01" }, rules: "", submissionRequirements: "", awardSettings: [{ awardName: "Best Overall" }, { awardName: "Best UX" }], organizerUserIds: [carol.id], createdByUserId: carol.id, visibility: "public", createdAt: now(), updatedAt: now(), version: 1 }).record;
    const race2 = stores.races.insert({ id: uid(), slug: "smart-investment-analyst", title: "智能投研助理", challengeBrief: "构建金融投研 Agent", status: "running", timeWindows: {}, rules: "", submissionRequirements: "", awardSettings: [], organizerUserIds: [carol.id], createdByUserId: carol.id, visibility: "public", createdAt: now(), updatedAt: now(), version: 1 }).record;

    // Registration for Alice
    const reg1 = stores.registrations.insert({ id: uid(), raceId: race1.id, userId: alice.id, status: "approved", submittedAt: now(), approvedAt: now(), approvedByUserId: carol.id, rejectedAt: null, rejectedReason: null, withdrawnAt: null, reviewFlags: [], createdAt: now(), updatedAt: now(), version: 1 }).record;

    // RaceProject for Alice
    stores.raceProjects.insert({ id: uid(), registrationId: reg1.id, raceId: race1.id, userId: alice.id, repoUrl: null, aggregateIngestionStatus: "not_configured", connectionHealth: "no_signal", authenticitySummary: {}, reviewFlags: [], currentPrimaryWorkId: null, createdAt: now(), updatedAt: now(), version: 1 });

    App.currentUser = alice;
    App.currentRaceId = race1.id;

    return { alice, bob, carol, admin, race1, race2, reg1 };
  }

  // ============ UI Helpers ============
  function $(sel) { return document.querySelector(sel); }
  function $$(sel) { return document.querySelectorAll(sel); }
  function html(sel, v) { const n = $(sel); if (n && v !== undefined) n.innerHTML = v; }
  function text(sel, v) { const n = $(sel); if (n && v !== undefined) n.textContent = v; }
  function show(sel) { const n = $(sel); if (n) n.style.display = ""; }
  function hide(sel) { const n = $(sel); if (n) n.style.display = "none"; }
  function val(sel) { const n = $(sel); return n ? (n.value || "").trim() : ""; }

  // ============ Page Navigation ============
  function setPage(name) {
    App.page = name;
    $$("[data-page-panel]").forEach((p) => p.classList.toggle("active", p.dataset.pagePanel === name));
    $$("[data-page]").forEach((b) => b.classList.toggle("active", b.dataset.page === name));
    if (name === "register") renderRegisterPage();
    if (name === "races") renderRacesPage();
    if (name === "my-races") renderMyRacesPage();
    if (name === "login") renderLoginPage();
    if (name === "home") renderHomePage();
  }

  // ============ Login Page ============
  function renderLoginPage() {
    const users = stores.users.all();
    html("#login-user-list",
      users.map((u) =>
        `<button class="login-user-card" data-user-id="${u.id}">
          <b>${u.displayName}</b>
          <span>${(u.roles || []).join(" / ") || "未分配角色"}</span>
          <small>${u.profile?.bio || ""}</small>
        </button>`
      ).join("")
    );
  }

  // ============ Home Page ============
  function renderHomePage() {
    const races = stores.races.all().filter((r) => r.visibility === "public");
    const u = App.currentUser;
    html("#home-user-greeting", u ? `<span>👋 ${u.displayName}</span>` : "");
    html("#home-race-list",
      races.map((r) => {
        const regs = stores.registrations.find((x) => x.raceId === r.id);
        const myReg = u ? regs.find((x) => x.userId === u.id) : null;
        const statusBadge = myReg
          ? `<span class="my-status ${myReg.status}">${statusLabel(myReg.status)}</span>`
          : (r.status === "registration" ? `<span class="my-status open">报名开放</span>` : "");
        return `<article class="race-card">
          <div class="race-card-head">
            <span class="race-status-badge ${r.status}">${statusLabel(r.status)}</span>
          </div>
          <h3>${r.title}</h3>
          <p>${r.challengeBrief}</p>
          <div class="race-card-meta">
            <span>🏇 ${regs.length} riders</span>
            ${statusBadge}
          </div>
          <div class="race-card-actions">
            ${myReg
              ? `<button data-page="my-races">查看我的参赛</button>`
              : (r.status === "registration"
                ? `<button class="primary" onclick="AppActions.register('${r.id}')">立即报名</button>`
                : `<button disabled>${statusLabel(r.status)}</button>`
              )
            }
          </div>
        </article>`;
      }).join("")
    );
  }

  function statusLabel(s) {
    const map = { draft: "草稿", published: "已发布", registration: "报名中", running: "进行中", submitting: "提交期", judging: "评审中", completed: "已结束", archived: "已归档", submitted: "已报名", approved: "已通过", rejected: "已拒绝", withdrawn: "已退赛" };
    return map[s] || s;
  }

  // ============ Register Page (核心报名 UI) ============
  function renderRegisterPage() {
    const races = stores.races.all().filter((r) => r.status === "registration" && r.visibility === "public");
    if (races.length === 0) {
      html("#register-content", `<div class="empty-state">🎯 当前没有开放报名的赛事</div>`);
      return;
    }
    html("#register-content",
      `<div class="register-intro">
        <h2>选择一场赛事报名</h2>
        <p>每个赛事每人只能报名一次。报名通过后系统会自动创建你的骑行工作区。</p>
      </div>
      <div class="register-race-list">
        ${races.map((r) => {
          const alreadyRegistered = stores.registrations.first((x) => x.raceId === r.id && x.userId === App.currentUser?.id);
          return `<article class="register-race-card ${alreadyRegistered ? "done" : ""}">
            <h3>${r.title}</h3>
            <p>${r.challengeBrief}</p>
            <div class="register-meta">
              <span>🏇 ${stores.registrations.find((x) => x.raceId === r.id).length} 人已报名</span>
            </div>
            ${alreadyRegistered
              ? `<div class="register-feedback ok">✅ 已报名 — 状态：${statusLabel(alreadyRegistered.status)}</div>`
              : `<div class="register-form" data-race-id="${r.id}">
                <button class="primary" onclick="AppActions.submitRegistration('${r.id}')">提交报名</button>
                <div class="register-constraint-hint">每个赛事每人限报一次，报名后不可重复提交</div>
              </div>`
            }
          </article>`;
        }).join("")}
      </div>
      <div id="register-result" class="register-result" style="display:none"></div>`
    );
  }

  function submitRegistration(raceId) {
    if (!App.currentUser) {
      showFeedback("register-result", "error", "请先登录后再报名。点击右上角 Login。");
      return;
    }
    if (!App.currentUser.roles.includes("rider")) {
      showFeedback("register-result", "error", "你的账号没有 rider 角色，无法报名参赛。");
      return;
    }
    const race = stores.races.get(raceId);
    if (!race || race.status !== "registration") {
      showFeedback("register-result", "error", "该赛事当前不开放报名。");
      return;
    }

    // === DEV-1 约束验证：唯一键 ===
    const existing = stores.registrations.first((x) => x.raceId === raceId && x.userId === App.currentUser.id);
    if (existing) {
      showFeedback("register-result", "error",
        `❌ 报名被拒绝：你已报名过「${race.title}」。<br><small>约束: UNIQUE(raceId, userId) — 一个 User 对同一 Race 最多一个 Registration</small>`
      );
      return;
    }

    // 执行报名
    const result = stores.registrations.insert({
      id: uid(), raceId, userId: App.currentUser.id, status: "submitted",
      submittedAt: now(), approvedAt: null, approvedByUserId: null,
      rejectedAt: null, rejectedReason: null, withdrawnAt: null, reviewFlags: [],
      createdAt: now(), updatedAt: now(), version: 1,
    });

    if (result.ok) {
      showFeedback("register-result", "ok",
        `✅ 报名成功！<br><small>Registration ID: ${result.record.id.slice(0,8)}…<br>状态: submitted → 等待主办方审核<br>审核通过后系统将自动创建 RaceProject（骑行工作区）</small>`
      );
      setTimeout(() => renderRegisterPage(), 1500);
    } else {
      showFeedback("register-result", "error", `❌ 报名失败: ${result.reason}`);
    }
  }

  function showFeedback(containerId, type, message) {
    const el = document.getElementById(containerId);
    if (!el) return;
    el.style.display = "block";
    el.className = `register-result ${type}`;
    el.innerHTML = message;
  }

  // ============ My Races Page ============
  function renderMyRacesPage() {
    const u = App.currentUser;
    if (!u) { html("#my-races-content", `<div class="empty-state">请先登录</div>`); return; }

    const myRegs = stores.registrations.find((x) => x.userId === u.id);
    if (myRegs.length === 0) {
      html("#my-races-content", `<div class="empty-state">你还没有报名任何赛事。<br><button class="primary" data-page="register" onclick="setPage('register')">去报名</button></div>`);
      return;
    }

    html("#my-races-content",
      `<h2>我的参赛</h2>
      ${myRegs.map((reg) => {
        const race = stores.races.get(reg.raceId);
        const rp = stores.raceProjects.first((x) => x.registrationId === reg.id);
        const work = stores.works.first((x) => x.registrationId === reg.id);
        const ccs = stores.caConnections.find((x) => x.raceProjectId === rp?.id);

        // === DEV-1 约束状态实时展示 ===
        const constraints = [];
        constraints.push({ label: "唯一 Registration", ok: true, detail: `(raceId, userId) 唯一键正常` });
        constraints.push({ label: "RaceProject 存在", ok: !!rp, detail: rp ? `aggregateIngestionStatus: ${rp.aggregateIngestionStatus}` : "Registration 未 approved 或无 RaceProject" });
        constraints.push({ label: "主 Work 唯一", ok: true, detail: work ? `已创建 Work: ${work.title}` : "尚未创建 Work" });
        constraints.push({ label: "CA 可多登记", ok: true, detail: `${ccs.length} 个 CAConnection 已登记` });

        return `<article class="my-race-card">
          <h3>${race?.title || "未知赛事"}</h3>
          <div class="my-race-status">
            <span>📋 Registration: <b>${statusLabel(reg.status)}</b></span>
            ${rp ? `<span>🚴 RaceProject: <b>${rp.aggregateIngestionStatus}</b></span>` : ""}
            ${work ? `<span>📦 Work: <b>${statusLabel(work.status)}</b></span>` : ""}
          </div>
          <div class="constraint-checks">
            <h4>DEV-1 约束校验</h4>
            ${constraints.map((c) => `<div class="constraint-row ${c.ok ? "pass" : "fail"}"><span>${c.ok ? "✓" : "✗"}</span> ${c.label}<small>${c.detail}</small></div>`).join("")}
          </div>
          ${reg.reviewFlags?.length > 0 ? `<div class="review-flags">⚠ 风险提示: ${reg.reviewFlags.map((f) => f.flagType).join(", ")}</div>` : ""}
        </article>`;
      }).join("")}`
    );
  }

  // ============ Races Page (公开赛事列表) ============
  function renderRacesPage() {
