    /* ====== 功能页面扩展样式 ====== */
    .page-login, .page-register, .page-my-races, .page-races {
      display: none; position: absolute; inset: 0; overflow-y: auto; padding: 20px 42px 40px;
    }
    .page-login.active, .page-register.active, .page-my-races.active, .page-races.active {
      display: block;
    }

    /* Login */
    .login-shell { max-width: 480px; margin: 60px auto 0; }
    .login-shell h1 { font-size: 42px; font-weight: 950; color: var(--blue-950); text-align: center; margin-bottom: 8px; }
    .login-shell .sub { text-align: center; color: var(--muted); margin-bottom: 32px; font-size: 16px; }
    .login-user-card { display: block; width: 100%; padding: 18px 24px; border: 1px solid var(--line); border-radius: 16px; background: var(--glass); margin-bottom: 10px; cursor: pointer; text-align: left; box-shadow: var(--shadow); backdrop-filter: blur(14px); transition: all 0.2s; }
    .login-user-card:hover { border-color: var(--blue-500); transform: translateY(-2px); }
    .login-user-card b { display: block; font-size: 20px; color: var(--blue-950); }
    .login-user-card span { display: block; margin-top: 4px; color: var(--blue-700); font-size: 13px; font-weight: 700; }
    .login-user-card small { display: block; margin-top: 4px; color: var(--muted); font-size: 13px; }

    /* Register */
    .register-intro { margin-bottom: 28px; }
    .register-intro h2 { font-size: 36px; font-weight: 950; color: var(--blue-950); margin-bottom: 8px; }
    .register-intro p { color: var(--muted); font-size: 16px; }
    .register-race-list { display: grid; grid-template-columns: repeat(2, 1fr); gap: 18px; }
    .register-race-card { padding: 24px; border: 1px solid var(--line); border-radius: 18px; background: var(--glass); box-shadow: var(--shadow); backdrop-filter: blur(14px); }
    .register-race-card.done { opacity: 0.65; }
    .register-race-card h3 { font-size: 26px; color: var(--blue-950); margin-bottom: 8px; }
    .register-race-card p { color: var(--muted); font-size: 15px; line-height: 1.45; }
    .register-meta { margin: 16px 0 12px; color: var(--blue-700); font-size: 14px; }
    .register-form { margin-top: 16px; }
