    .register-result.ok { background: #d1fae5; color: #065f46; border: 1px solid #6ee7b7; }
    .register-result.error { background: #fee2e2; color: #991b1b; border: 1px solid #fca5a5; }
    .register-result small { font-size: 12px; opacity: 0.8; display: block; margin-top: 6px; }

    /* My Races */
    .my-race-card { padding: 24px; border: 1px solid var(--line); border-radius: 18px; background: var(--glass); box-shadow: var(--shadow); backdrop-filter: blur(14px); margin-bottom: 18px; }
