    /* Race card */
    .race-card { padding: 24px; border: 1px solid var(--line); border-radius: 18px; background: var(--glass); box-shadow: var(--shadow); backdrop-filter: blur(14px); margin-bottom: 16px; }
    .race-card-head { margin-bottom: 10px; }
    .race-status-badge { display: inline-block; padding: 5px 12px; border-radius: 8px; font-size: 12px; font-weight: 950; text-transform: uppercase; }
    .race-status-badge.registration { background: #d1fae5; color: #065f46; }
    .race-status-badge.running { background: #eaf3ff; color: var(--blue-700); }
    .race-status-badge.completed { background: #f3f4f6; color: #6b7280; }
    .race-status-badge.judging { background: #fef3c7; color: #92400e; }
    .race-card h3 { font-size: 24px; color: var(--blue-950); margin-bottom: 8px; }
    .race-card p { color: var(--muted); font-size: 14px; line-height: 1.45; margin-bottom: 12px; }
    .race-card-meta { display: flex; gap: 12px; margin-bottom: 14px; font-size: 13px; color: var(--blue-800); }
    .my-status { display: inline-block; padding: 4px 10px; border-radius: 8px; font-size: 12px; font-weight: 700; }
    .my-status.approved { background: #d1fae5; color: #065f46; }
    .my-status.submitted { background: #eaf3ff; color: var(--blue-700); }
    .my-status.open { background: #fef3c7; color: #92400e; }
