  // ========================
  describe("AC-1: 唯一 Registration 约束", () => {
    it("AC-1.1 — 首次报名正常通过", () => {
      const race = createRace({ status: "registration" }).record;
      const user = createUser({ roles: ["rider"] }).record;
      const result = submitRegistration(race.id, user.id);
      assert.ok(result.ok);
