    });

    it("AC-3.4 — 归属错误的 CAConnection 数据被拒收", () => {
      const rp = createRaceProject().record;
      const cc = createCAConnection({
        raceProjectId: rp.id, registrationId: rp.registrationId,
        ingestionStatus: "connected", authenticityStatus: "verified",
      }).record;
      const ses = createSession({
        caConnectionId: cc.id, raceProjectId: rp.id, registrationId: "wrong-reg",
      }).record;
      const r = canEnterSession(ses);
      assert.equal(r.ok, false);
      assert.equal(r.reason, "归属错误");
    });

    it("AC-3.5 — 被禁用的 CAConnection 数据被拒收", () => {
      const rp = createRaceProject().record;
      const cc = createCAConnection({
        raceProjectId: rp.id, ingestionStatus: "connected",
        authenticityStatus: "verified", disabledAt: now(),
      }).record;
      const ses = createSession({ caConnectionId: cc.id }).record;
      const r = canEnterSession(ses);
      assert.equal(r.ok, false);
      assert.equal(r.reason, "CAConnection 已被禁用");
    });

    it("AC-3.6 — 混合场景：部分有效、部分无效", () => {
