      const rp = createRaceProject().record;
      cc = createCAConnection({
        raceProjectId: rp.id, registrationId: rp.registrationId, userId: rp.userId, raceId: rp.raceId,
        ingestionStatus: "connected", authenticityStatus: "verified",
        appInstanceId: "app-001", deviceKeyId: "key-001", deviceKeyFingerprint: "fp-001",
      }).record;
      registerDeviceKey("app-001", "key-001", "mock-pem");
    });

    function validMsg(o = {}) {
      const body = { event: "task_completed", taskId: "t1" };
      const n = normalizeBody(body);
      return { appInstanceId: "app-001", deviceKeyId: "key-001", nonce: uid(), sequence: Math.floor(Math.random() * 100000) + 1000, timestamp: new Date(Date.now() - 1000).toISOString(), caConnectionId: cc.id, messageId: uid(), idempotencyKey: uid(), schemaVersion: "ary.ca.riding_signal.v0.1", signature: { algorithm: "ecdsa-p256", bodyHash: computeBodyHash(n), value: "valid-sig-abcd" }, body, ...o };
    }

    it("AC-4.1 — 全量校验通过", () => { assert.ok(verifyMessage(validMsg()).passed); });
    it("AC-4.2 — 签名不一致 → 隔离审计", () => {
      const r = verifyMessage(validMsg({ signature: { algorithm: "ecdsa-p256", bodyHash: "bad", value: "bad" } }));
      assert.equal(r.passed, false);
      assert.equal(stores.caQuarantineAudits.count(), 1);
    });
    it("AC-4.3 — nonce 重放 → 隔离审计", () => {
      const m = validMsg(); verifyMessage(m);
      const r = verifyMessage(m);
      assert.equal(r.passed, false);
      assert.equal(r.verificationResult, "nonce_replayed");
    });
    it("AC-4.4 — sequence 回退 → 隔离审计", () => {
      verifyMessage(validMsg({ sequence: 100 }));
      assert.equal(verifyMessage(validMsg({ sequence: 50 })).passed, false);
    });
    it("AC-4.5 — deviceKey 已撤销 → 隔离审计", () => {
      revokeDeviceKey("key-001");
      assert.equal(verifyMessage(validMsg()).passed, false);
    });
    it("AC-4.6 — appInstance 未知 → 隔离审计", () => {
      assert.equal(verifyMessage(validMsg({ appInstanceId: "unknown" })).passed, false);
    });
    it("AC-4.7 — 审计可见性：summaryFilter 不暴露 rawMetadata", () => {
      verifyMessage(validMsg({ appInstanceId: "unknown" }));
      const q = stores.caQuarantineAudits.all()[0];
      const s = quarantineSummaryFilter(q);
      assert.ok(s.failureReason);
      assert.equal(s.rawMessageMetadata, undefined);
      assert.ok(q.rawMessageMetadata);
    });
