  // ========================
  // 鉴权作用域
  // ========================
  describe("鉴权作用域", () => {
    it("ownGate — User 只能访问自己的资源", () => {
      const u = createUser({ roles: ["rider"] }).record;
      assert.ok(ownGate({ userId: u.id }, u));
      assert.equal(ownGate({ userId: "other" }, u), false);
    });
    it("assignedGate — Judge 只能访问已分配的作品", () => {
      const j = createUser({ roles: ["judge"] }).record;
      const w = createWork().record;
      assert.equal(assignedGate(w.id, j), false);
