    });
    it("managedRaceGate — Organizer 只能管理自己的 Race", () => {
      const o = createUser({ roles: ["organizer"] }).record;
      const r = createRace({ organizerUserIds: [o.id], createdByUserId: o.id }).record;
      assert.ok(managedRaceGate({ raceId: r.id }, o));
      assert.equal(managedRaceGate({ raceId: "other" }, o), false);
    });
    it("adminGate — Admin 拥有 system 权限", () => {
      assert.ok(adminGate(createUser({ roles: ["admin"] }).record));
      assert.equal(adminGate(createUser({ roles: ["rider"] }).record), false);
    });
  });
});

