          <span style="padding:3px 10px;border-radius:6px;background:${evidences.length > 0 ? "#d1fae5" : "#f3f4f6"};color:${evidences.length > 0 ? "#065f46" : "#6b7280"};font-weight:700;">Projection / Report 输入</span>
        </div>` : ""}
      </article>`;
