{"content":"// ARY MVP — Test Shims (browser-side only).
// Must be loaded AFTER app-core.js.
// This file ONLY provides test-specific forgery / injection abilities.
// All production runtime logic lives in app-core.js (window.ARY_CORE).

(function () {
  "use strict";

  if (!window.ARY_CORE) {
    console.warn("test-modules.js: ARY_CORE not found — app-core.js must load first");
    return;
  }

  const { uid, now, stores, caVerifier } = window.ARY_CORE;

  // ============ IDENTITY FORGERY (Demo login) ============
  // The production app would use real GitHub OAuth.
  // These provide pre-built identities for interactive testing.

  const identities = {
    alice: { id: null, displayName: "Alice Chen", roles: ["rider"], bio: "HKU CS / 大三" },
    bob:   { id: null, displayName: "Bob Xu", roles: ["rider", "judge"], bio: "FinTech Studio" },
    carol: { id: null, displayName: "Carol Wang", roles: ["organizer"], bio: "赛事主办方" },
    admin: { id: null, displayName: "Admin", roles: ["admin"], bio: "" },
  };

  function seedIdentities() {
    for (const [key, id] of Object.entries(identities)) {
      const result = stores.users.insert({
        id: uid(), githubAccountId: `gh-${key}`, slug: key,
        displayName: id.displayName,
        profile: { bio: id.bio, avatarUrl: "" },
        roles: id.roles,
        profileCompletionStatus: "complete", status: "active",
        createdAt: now(), updatedAt: now(), version: 1,
      });
      id.id = result.record?.id;
    }
    return identities;
  }

  // ============ MESSAGE FORGERY (CA test messages) ============
  // These simulate what a real DCR Desktop App would send.
  // Production would receive real signed messages from the app.

  let testSeqCounter = 1000;

  function sendTestMsg(caId, type) {
    const { simpleHash, normalizeBody } = caVerifier;
    const cc = stores.caConnections.get(caId);
    if (!cc) return { ok: false, reason: "CAConnection 不存在" };

    const body = { event: "test_verification", ts: now() };
    const sortedKeys = Object.keys(body).sort();
    const sortedBody = {};
    sortedKeys.forEach((k) => (sortedBody[k] = body[k]));
    const normalized = JSON.stringify(sortedBody);
    let h = 0;
    for (let i = 0; i < normalized.length; i++) { h = ((h << 5) - h + normalized.charCodeAt(i)) | 0; }
    const computedHash = h.toString(16);

    const baseMsg = {
      appInstanceId: type === "unknownapp" ? "bad-app" : "app-test",
      deviceKeyId: type === "keyrevoke" ? "key-old" : "key-test",
      nonce: type === "replay" ? "dup-nonce-123" : uid(),
      sequence: type === "seqback" ? 10 : ++testSeqCounter,
      timestamp: new Date(Date.now() - 1000).toISOString(),
      caConnectionId: caId, messageId: uid(),
      idempotencyKey: type === "replay" ? "dup-nonce-123" : uid(),
      schemaVersion: "ary.ca.riding_signal.v0.1",
      signature: {
        algorithm: "ecdsa-p256",
        bodyHash: type === "badhash" ? "bad-hash-xxx" : computedHash,
        value: type === "badhash" ? "short" : "valid-sig-testing-ok",
      },
      body,
    };
    return caVerifier.verifyMessage(baseMsg);
  }

  // ============ KEY INJECTION (fake DCR Desktop App keys) ============
  function injectDefaultKeys() {
    caVerifier.registerDeviceKey("app-test", "key-test");
  }

  // ============ Attach to ARY_CORE ============
  window.ARY_CORE.testShims = {
    identities,
    seedIdentities,
    sendTestMsg,
    injectDefaultKeys,
  };

  // Legacy
  window.ARY_TEST = window.ARY_CORE;
})();
