let testSeqCounter = 1000;
function sendTestMsg(caId, type) {
  const cc = stores.caConnections.get(caId);
  if (!cc) return;
  const body = { event: "test_verification", ts: now() };
  // Compute body hash matching verifyMessage's algorithm
  const sortedKeys = Object.keys(body).sort();
  const sortedBody = {};
  sortedKeys.forEach((k) => (sortedBody[k] = body[k]));
  const normalized = JSON.stringify(sortedBody);
  let bodyHash = 0;
  for (let i = 0; i < normalized.length; i++) { bodyHash = ((bodyHash << 5) - bodyHash + normalized.charCodeAt(i)) | 0; }
  const computedHash = bodyHash.toString(16);

  const baseMsg = {
    appInstanceId: type === "unknownapp" ? "bad-app" : "app-test",
    deviceKeyId: type === "keyrevoke" ? "key-old" : "key-test",
    nonce: type === "replay" ? "dup-nonce-123" : uid(),
    sequence: type === "seqback" ? 10 : ++testSeqCounter,
    timestamp: new Date(Date.now() - 1000).toISOString(),
    caConnectionId: caId, messageId: uid(), idempotencyKey: type === "replay" ? "dup-nonce-123" : uid(),
    schemaVersion: "ary.ca.riding_signal.v0.1",
    signature: { algorithm: "ecdsa-p256", bodyHash: type === "badhash" ? "bad-hash-xxx" : computedHash, value: type === "badhash" ? "short" : "valid-sig-testing-ok" },
    body,
  };
  const result = caVerifier.verifyMessage(baseMsg);
  const labelMap = { valid: "合法消息", badhash: "Hash 错误", replay: "重放", seqback: "序列回退", keyrevoke: "Key 撤销", unknownapp: "App 未知" };
  showFeedback("ca-verify-result", result.passed ? "ok" : "error",
    `${result.passed ? "✅ 校验通过" : "❌ 验签失败"}: ${result.verificationResult}<br><small>类型: ${labelMap[type]} | 隔离审计: ${stores.caQuarantineAudits.count()} 条</small>`
  );
  setTimeout(renderCAVerifyPage, 800);
}

